INSERT INTO public.state_law_provisions
  (act_id, state_code, topic, rule_kind, threshold_numeric, threshold_unit, summary, statute_citation, source_url, source_date, effective_year)
SELECT a.id, 'NH', v.topic, v.rule_kind, v.threshold_numeric, v.threshold_unit, v.summary, v.citation, v.url, DATE '2026-06-11', 2026
FROM public.state_landlord_tenant_acts a CROSS JOIN (VALUES
  ('deposit_max_months', 'max', 1::numeric, 'months of rent', 'A security deposit may not exceed 1 month of rent.', 'RSA 540-A:6, I(a)', 'https://gc.nh.gov/rsa/html/lv/540-A/540-A-6.htm'),
  ('deposit_return_days', 'max', 30::numeric, 'days', 'The deposit must be returned within 30 days after the tenancy ends.', 'RSA 540-A:7', 'https://gc.nh.gov/rsa/html/lv/540-A/540-A-7.htm'),
  ('notice_to_vacate_days', 'min', 30::numeric, 'days', 'Ending a month-to-month tenancy generally requires at least 30 days'' notice.', 'RSA 540:3, II', 'https://gc.nh.gov/rsa/html/lv/540/540-3.htm')
) AS v(topic, rule_kind, threshold_numeric, threshold_unit, summary, citation, url)
WHERE a.state_code = 'NH' AND a.act_key = 'residential' AND a.effective_year = 2026;

